import React from "react";

export default function Sidebar({ user, rooms, activeRoom, onSelectRoom, onCreateRoomOpen, onJoinRoom, onLeaveRoom, onDeleteRoom, onLogout, theme, onThemeChange, connected }) {
  const themes = [
    { id: "ocean", label: "Ocean Blue" },
    { id: "sunset", label: "Sunset Orange" },
    { id: "forest", label: "Forest Green" },
    { id: "midnight", label: "Midnight" },
    { id: "lavender", label: "Lavender" }
  ];

  return (
    <aside className="sidebar glass">
      <div className="sidebar-top">
        <div className="logo-row">
          <img src="/wavvy-logo.svg" alt="Wavvy" className="mini-logo" />
          <div>
            <h2>Wavvy</h2>
            <span className={connected ? "status connected" : "status disconnected"}>{connected ? "Online" : "Connecting..."}</span>
          </div>
        </div>
        <div className="user-pill"><strong>{user?.username}</strong><small>{user?.email}</small></div>
        <div className="theme-picker">
          <label htmlFor="theme-select">Theme</label>
          <select id="theme-select" value={theme} onChange={(event) => onThemeChange(event.target.value)}>
            {themes.map((item) => <option value={item.id} key={item.id}>{item.label}</option>)}
          </select>
        </div>
        <button className="primary-btn" onClick={onCreateRoomOpen} type="button">+ Create New</button>
      </div>

      <div className="room-list">
        {rooms.map((room) => {
          const isMember = room.members?.some((member) => (member._id || member.id) === user?.id);
          const isAdmin = room.admins?.some((admin) => (admin._id || admin.id) === user?.id) || (room.createdBy?._id || room.createdBy?.id) === user?.id;
          const isActive = activeRoom?._id === room._id;
          return (
            <article key={room._id} className={isActive ? "room-card active" : "room-card"}>
              <button type="button" onClick={() => onSelectRoom(room)} className="room-main-btn">
                <strong>{room.name}</strong><span>{room.description || "No description"}</span><small>{room.members?.length || 0} members</small>
              </button>
              <div className="room-actions">
                {!isMember ? <button className="ghost-btn" type="button" onClick={() => onJoinRoom(room._id)}>Join</button> : null}
                {isMember ? <button className="danger-btn" type="button" onClick={() => onLeaveRoom(room._id)}>Leave</button> : null}
                {isAdmin ? <button className="danger-btn" type="button" onClick={() => onDeleteRoom(room._id)}>Delete</button> : null}
              </div>
            </article>
          );
        })}
      </div>

      <button className="ghost-btn logout-btn" onClick={onLogout} type="button">Logout</button>
    </aside>
  );
}
